/**
 * EventEmitter - Simple pub/sub system for data events
 *
 * NO SVELTE DEPENDENCIES - Pure TypeScript
 *
 * Provides one-way data flow: business logic emits events,
 * UI components subscribe and react.
 */
export class EventEmitter {
    listeners = new Map();
    /**
     * Subscribe to an event
     * @param event Event name
     * @param handler Callback function
     * @returns Unsubscribe function
     */
    on(event, handler) {
        if (!this.listeners.has(event)) {
            this.listeners.set(event, new Set());
        }
        this.listeners.get(event).add(handler);
        // Return unsubscribe function
        return () => {
            const handlers = this.listeners.get(event);
            if (handlers) {
                handlers.delete(handler);
                // Clean up empty sets
                if (handlers.size === 0) {
                    this.listeners.delete(event);
                }
            }
        };
    }
    /**
     * Emit an event to all subscribers
     * @param event Event name
     * @param payload Event payload
     */
    emit(event, payload) {
        const handlers = this.listeners.get(event);
        if (handlers) {
            // Call each handler in the order they were registered
            handlers.forEach(handler => {
                try {
                    handler(payload);
                }
                catch (error) {
                    console.error(`Error in event handler for "${String(event)}":`, error);
                }
            });
        }
    }
    /**
     * Subscribe to an event, but only fire once
     * @param event Event name
     * @param handler Callback function
     * @returns Unsubscribe function
     */
    once(event, handler) {
        const wrappedHandler = (payload) => {
            unsubscribe();
            handler(payload);
        };
        const unsubscribe = this.on(event, wrappedHandler);
        return unsubscribe;
    }
    /**
     * Remove all listeners for an event, or all events if no event specified
     * @param event Optional event name
     */
    off(event) {
        if (event) {
            this.listeners.delete(event);
        }
        else {
            this.listeners.clear();
        }
    }
    /**
     * Get count of listeners for an event
     * @param event Event name
     * @returns Number of listeners
     */
    listenerCount(event) {
        const handlers = this.listeners.get(event);
        return handlers ? handlers.size : 0;
    }
    /**
     * Get all event names that have listeners
     * @returns Array of event names
     */
    eventNames() {
        return Array.from(this.listeners.keys());
    }
}
